export type ScoreType = DecodeScores;
type ScoreTypeSetValue = <K extends keyof ScoreType>(color: AllianceColor, key: K, value: ScoreType[K]) => void
type AllianceScoreTypeSetValue = <K extends keyof ScoreType>(key: K, value: ScoreType[K]) => void

function getNoShowString(score: DecodeScores, teamPos: 1 | 2, isElims: boolean ) {
    if (isElims) {
        return "Not Playing";
    } else {
        if (score[`noshow${teamPos}`] === 1) return "No Team";
        if (score[`noshow${teamPos}`] === 2) return "No Robot";
    }
}

const classifierPositions = [1, 2, 3, 4, 5, 6, 7, 8, 9];
const colorCapsNames = {
    [AllianceColor.RED]: 'Red',
    [AllianceColor.BLUE]: 'Blue'
}

function replaceClassifierState(state: ArtifactType, position: number, existing: ArtifactType[]): ArtifactType[] {
    const newState = [...existing];
    if (position < 0 || position >= newState.length) {
        throw new Error(`Invalid position ${position} for classifier state`);
    }
    newState[position] = state;
    return newState;
}

function invalidArtifactIndexes(artifacts: ArtifactType[]) {
    const indexes: number[] = [];
    let foundNone = false;
    artifacts.forEach((artifact, index) => {
        if (artifact === ArtifactType.NONE) {
            foundNone = true;
        } else if (foundNone) {
            indexes.push(index);
        }
    });
    return indexes;
}

const allianceColors = [AllianceColor.RED, AllianceColor.BLUE]
const robotArr = [1, 2] as const;

const emptyFields = {
    [AllianceColor.RED]: [],
    [AllianceColor.BLUE]: [],
}

export const autoFields: Record<RefereePosition, Record<AllianceColor, (keyof ScoreType)[]>> = {
    [RefereePosition.SCORING_RED]: {
        [AllianceColor.RED]: [],
        [AllianceColor.BLUE]: ["autoClassifiedArtifacts", "autoOverflowArtifacts", "autoClassifierState", "robot1Auto", "robot2Auto"],
    },
    [RefereePosition.SCORING_BLUE]: {
        [AllianceColor.RED]: ["autoClassifiedArtifacts", "autoOverflowArtifacts", "autoClassifierState", "robot1Auto", "robot2Auto"],
        [AllianceColor.BLUE]: [],
    },
    [RefereePosition.PENALTY_RED]: emptyFields,
    [RefereePosition.PENALTY_BLUE]: emptyFields,
}

export const teleopFields: Record<RefereePosition, Record<AllianceColor, (keyof ScoreType)[]>> = {
    [RefereePosition.SCORING_RED]: {
        [AllianceColor.RED]: ["robot1Teleop", "robot2Teleop"],
        [AllianceColor.BLUE]: ["teleopClassifiedArtifacts", "teleopOverflowArtifacts", "teleopClassifierState", "teleopDepotArtifacts"],
    },
    [RefereePosition.SCORING_BLUE]: {
        [AllianceColor.RED]: ["teleopClassifiedArtifacts", "teleopOverflowArtifacts", "teleopClassifierState", "teleopDepotArtifacts"],
        [AllianceColor.BLUE]: ["robot1Teleop", "robot2Teleop"],
    },
    [RefereePosition.PENALTY_RED]: emptyFields,
    [RefereePosition.PENALTY_BLUE]: emptyFields,
}

export const penaltyFields: Record<RefereePosition, Record<AllianceColor, (keyof ScoreType)[]>> = {
    [RefereePosition.SCORING_RED]: window.penaltyTabletEnabled ? emptyFields : {
        [AllianceColor.RED]: ["ownMajorFouls", "ownMinorFouls"],
        [AllianceColor.BLUE]: ["otherMajorFouls", "otherMinorFouls"],
    },
    [RefereePosition.SCORING_BLUE]: window.penaltyTabletEnabled ? emptyFields : {
        [AllianceColor.RED]: ["otherMajorFouls", "otherMinorFouls"],
        [AllianceColor.BLUE]: ["ownMajorFouls", "ownMinorFouls"],
    },
    [RefereePosition.PENALTY_RED]:  window.penaltyTabletEnabled ? {
        [AllianceColor.RED]: ["ownMajorFouls", "ownMinorFouls"],
        [AllianceColor.BLUE]: ["otherMajorFouls", "otherMinorFouls"],
    } : emptyFields,
    [RefereePosition.PENALTY_BLUE]: window.penaltyTabletEnabled ? {
        [AllianceColor.RED]: ["otherMajorFouls", "otherMinorFouls"],
        [AllianceColor.BLUE]: ["ownMajorFouls", "ownMinorFouls"],
    } : emptyFields,
}

function isPenalty(position: RefereePosition) {
    return position === RefereePosition.PENALTY_BLUE || position === RefereePosition.PENALTY_RED;
}

function Classifier({ color, score, setScoreValue, field }: { color: AllianceColor, score: DecodeScores, setScoreValue: AllianceScoreTypeSetValue, field: 'autoClassifierState' | 'teleopClassifierState' }) {
    const invalidIndexes = invalidArtifactIndexes(score[field]);
    const idPrefix = useId();
    const gateSvg = useAsset('img/decode/gate.svg');
    return <>
        <div className="form-group row justify-content-center">
            <table className={"table table-bordered table-sm col-10 text-center classifier "+color}>
                <thead>
                <tr>
                    <th colSpan={5}>{colorCapsNames[color]} PATTERN Scoring</th>
                </tr>
                <tr>
                    <th>GATE <ReactSVG src={gateSvg} className={"d-inline-block"}/></th>
                    <th>GREEN</th>
                    <th>PURPLE</th>
                    <th>NONE</th>
                    <th></th>
                </tr>
                </thead>
                <tbody>
                {classifierPositions.map((pos, idx) => <tr key={pos}
                                                           className={invalidIndexes.includes(idx) ? 'table-danger' : ''}>
                    <td>{pos}</td>
                    {[ArtifactType.GREEN, ArtifactType.PURPLE, ArtifactType.NONE].map((type) => (
                        <td key={type}>
                            <div className="btn-group-toggle" data-toggle="buttons">
                                <label
                                    className={`btn btn-outline-secondary artifactLabel ` +
                                               `${type.toString().toLowerCase()}-artifact ` +
                                               `position-${pos} ` +
                                               `${score[field][pos - 1] == type ? 'active' : ''}`}>
                                    <input type="radio" name={`${idPrefix}-${field}${pos}`}
                                           checked={score[field][pos - 1] == type}
                                           onChange={(e) => (e.target as HTMLInputElement).checked ? setScoreValue(field, replaceClassifierState(type, pos - 1, score[field])) : null}/>
                                    <Artifact value={type}/>
                                </label>
                            </div>
                        </td>))}
                    <td style={{verticalAlign: "middle"}}>
                        <div className={"mx-auto"} style={{width: 'fit-content'}}>
                            <Artifact value={score[field][pos - 1]}/>
                        </div>
                    </td>
                </tr>)}
                </tbody>
                <tfoot>
                <tr>
                    <th>SQUARE <i className={`far fa-fw fa-square`} style={{fontSize: '20px'}}></i></th>
                    <th>GREEN</th>
                    <th>PURPLE</th>
                    <th>NONE</th>
                    <th></th>
                </tr>
                </tfoot>
            </table>
        </div>
    </>
}

export function Init({scores, setupScores, setScoreValue, robots, alliance, isReview, currentBubble, setCurrentBubble, match} : {
    scores: Record<AllianceColor, DecodeScores>,
    setupScores: DecodeScores,
    setScoreValue: ScoreTypeSetValue,
    robots: Record<AllianceColor, Robots>,
    alliance: AllianceColor,
    isReview?: boolean,
    currentBubble?: BubbleType,
    setCurrentBubble?: (currentBubble : BubbleType) => void,
    match: RefMatch<DecodeScores>
}) {
    const isElims = match.type === 'ELIMS';
    const threeTeamAlliance = match[allianceToKey(alliance)].team3 > 0
    // Convert between noshow value and the toggle order:
    //      0 = present, 1 = no show, 2 = no robot (keep 0 & 1 the same as before to prevent unintended side-effects)
    //      This means > 0 is a check for score validity (ie disabled if > 0), while == 1 if a check for no-show
    //      These could be simplified but exploding the logic is easier to read.
    const noshowToToggleValue = (v: number) => {
        if (isElims) {
            return v ? 0 : 1;
        } else {
            if (v === 2) return 1;
            if (v === 1) return 0;
            if (v === 0) return 2;
        }
    }
    const toggleValueToNoshow = (v: number | undefined) => {
        if (isElims) {
            return v === 1 ? 0 : 1;
        } else {
            if (v === 0) return 1;
            if (v === 1) return 2;
            if (v === 2) return 0;
        }
    }
    const teamString = alliance === AllianceColor.RED ? 'Red' : 'Blue';
    return <>
        <div className="form-group row justify-content-center">
            <div className={"col-12 col-sm-10 col-lg-5 "}>
                <div className={"initGroup text-center "+alliance}>
                    <div className={"h3"}>{teamString} Alliance Teams:</div>
                    <br/>
                    {[match[allianceToKey(alliance)].team1, match[allianceToKey(alliance)].team2, match[allianceToKey(alliance)].team3].map((t, idx) => [t, idx + 1] as [number, 1 | 2 | 3]).filter(t => t[0]).map(team => {
                        const [t, teamPos] = team;
                        const options = isElims ? ["Not Playing", "On Field"] : ['No Team', 'No Robot', 'Present'];
                        return <div className="form-group row justify-content-center" key={teamPos}>
                            <Toggle label={`Team ${match[allianceToKey(alliance)][`team${teamPos}Display`]} Present:`} options={options} half={true}
                                    value={noshowToToggleValue(setupScores[`noshow${teamPos}`])} color={alliance}
                                    setValue={(val) => {
                                        let noShowVal = toggleValueToNoshow(val) ?? 0;
                                        setScoreValue(alliance, `noshow${teamPos}`, noShowVal);
                                        if (!isElims) {
                                            const qualsTeamPos = teamPos as 1 | 2; // can't have 3rd team in quals
                                            setScoreValue(alliance, `dq${qualsTeamPos}`, noShowVal === 1 ? 1 : 0);
                                        }
                                    }}/>
                        </div>
                    })}
                </div>
            </div>
        </div>
    </>
}

export function Auto({scores, setScoreValue, robots, position, isReview, currentBubble, setCurrentBubble, match} : {
    scores: Record<AllianceColor, DecodeScores>,
    setScoreValue: ScoreTypeSetValue,
    robots: Record<AllianceColor, Robots>,
    position: RefereePosition,
    isReview?: boolean,
    currentBubble?: BubbleType,
    setCurrentBubble?: (currentBubble : BubbleType) => void,
    match: RefMatch<DecodeScores>
}) {
    const myFields = autoFields[position]
    for (const r of robotArr) {
        for(const c of allianceColors) {
            if (myFields[c].includes(`robot${r}Auto`) && !robots[c][`robot${r}`] && scores[c][`robot${r}Auto`] > 0) {
                setScoreValue(c, `robot${r}Auto`, 0);
            }
        }
    }
    return <>
        <TrainingBubble type={BubbleType.AUTO_SAMPLES_SPECIMENS} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>

        {allianceColors.some(c => myFields[c].some(f => f.includes("autoOverflowArtifacts") || f.includes("autoClassifiedArtifacts"))) ? <div className="form-group row justify-content-center">
            <div className={"col-12 col-sm-10 col-lg-5 "}>
                {allianceColors.map(c =>
                    myFields[c].includes("autoOverflowArtifacts") ? <Counter key={c}
                    label={`OVERFLOW ARTIFACTS`} color={c}
                    limit={1000} large={true}
                    value={scores[c].autoOverflowArtifacts}
                    setValue={(val) => {
                        setScoreValue(c, "autoOverflowArtifacts", val)
                    }} /> : null)}

                {allianceColors.map(c =>
                    myFields[c].includes("autoClassifiedArtifacts") ? <Counter key={c}
                         label={`CLASSIFIED ARTIFACTS`} color={c} limit={1000}
                         value={scores[c].autoClassifiedArtifacts} large={true}
                         setValue={(val) => {
                             setScoreValue(c, "autoClassifiedArtifacts", val)
                         }}
                /> : null)}
            </div>
        </div> : null}

        <TrainingBubble type={BubbleType.AUTO_LOCATION} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {allianceColors.some(c => myFields[c].some(f => robotArr.some(num => f.includes(`robot${num}Auto`)))) ? <div className="form-group row justify-content-center">
            {robotArr.map(num => allianceColors.map(c => myFields[c].includes(`robot${num}Auto`) ?
                <Toggle key={`${num}-${c}`} color={c}
                        label={`${colorCapsNames[c]} ${num} LEAVE (${robots[c][`robot${num}Display`] || getNoShowString(scores[c], num, match.type === "ELIMS")}):`}
                        options={["No", "Yes"]} value={scores[c][`robot${num}Auto`]}
                        setValue={(val) => setScoreValue(c, `robot${num}Auto`, val)} disabled={!robots[c][`robot${num}`]} />
                : null))}
        </div> : null}

        <TrainingBubble type={BubbleType.AUTO_FOULS} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {isReview ? null : <Penalties scores={scores} setScoreValue={setScoreValue} position={position} />}

        <TrainingBubble type={BubbleType.AUTO_PATTERN} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {allianceColors.map(c =>
            myFields[c].includes("autoClassifierState") ?
                <Classifier key={c} color={c} score={scores[c]} setScoreValue={(field, value) => setScoreValue(c, field, value)}
                            field={"autoClassifierState"}/> : null)}

        <TrainingBubble type={BubbleType.AUTO_SUBMIT} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
    </>
}

export function Teleop({ scores, setScoreValue, robots, position, currentBubble, setCurrentBubble, match, isReview }: {
    scores: Record<AllianceColor, DecodeScores>,
    setScoreValue: ScoreTypeSetValue,
    robots: Record<AllianceColor, Robots>,
    position: RefereePosition,
    currentBubble?: BubbleType,
    setCurrentBubble?: (currentType: BubbleType) => void,
    match: RefMatch<DecodeScores>,
    isReview?: boolean,
}) {
    const myFields = teleopFields[position]
    return <>
        <TrainingBubble type={BubbleType.TELEOP_ARTIFACT} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {allianceColors.some(c => myFields[c].some(f => f.includes("teleopOverflowArtifacts") || f.includes("teleopClassifiedArtifacts"))) ? <div className="form-group row justify-content-center ">
            <div className={"col-12 col-sm-10 col-lg-5 "}>
                {allianceColors.map(c =>
                    myFields[c].includes("teleopOverflowArtifacts") ? <Counter key={c}
                         label={`OVERFLOW ARTIFACTS`} color={c} limit={1000} large={true}
                         value={scores[c].teleopOverflowArtifacts}
                         setValue={(val) => {
                             setScoreValue(c, "teleopOverflowArtifacts", val)
                         }} /> : null)}

                {allianceColors.map(c =>
                    myFields[c].includes("teleopClassifiedArtifacts") ? <Counter key={c}
                         label={`CLASSIFIED ARTIFACTS`} color={c} limit={1000} large={true}
                         value={scores[c].teleopClassifiedArtifacts}
                         setValue={(val) => {
                             setScoreValue(c, "teleopClassifiedArtifacts", val)
                         }} />: null)}
            </div>
        </div> : null}

        <TrainingBubble type={BubbleType.TELEOP_LOCATION} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {allianceColors.some(c => myFields[c].some(f => robotArr.some(num => f.includes(`robot${num}Teleop`)))) ? <div className="form-group row justify-content-center">
            {robotArr.map(num => allianceColors.map(c => myFields[c].includes(`robot${num}Teleop`) ?
                <Toggle key={`${num}-${c}`} color={c}
                        label={`${colorCapsNames[c]} ${num} BASE (${robots[c][`robot${num}Display`] || getNoShowString(scores[c], num, match.type === "ELIMS")}):`}
                        options={["No", "Partial", "Full"]} value={scores[c][`robot${num}Teleop`]}
                        setValue={(val) => setScoreValue(c, `robot${num}Teleop`, val)} disabled={!robots[c][`robot${num}`]} />
                : null))}
        </div> : null}

        <TrainingBubble type={BubbleType.TELEOP_DEPOT} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {allianceColors.some(c => myFields[c].some(f => robotArr.some(num => f.includes(`robot${num}Teleop`)))) ? <div className="form-group row justify-content-center">
            <div className={"col-12 col-sm-10 col-lg-5 "}>
                {allianceColors.map(c =>
                    myFields[c].includes("teleopDepotArtifacts") ? <Counter  key={c}
                         label={`DEPOT ARTIFACTS`} color={c} limit={1000}
                         value={scores[c].teleopDepotArtifacts}
                         setValue={(val) => {
                             setScoreValue(c, "teleopDepotArtifacts", val)
                         }} /> : null)}
            </div>
        </div> : null}

        <TrainingBubble type={BubbleType.TELEOP_FOULS} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {isReview ? null : <Penalties scores={scores} setScoreValue={setScoreValue} position={position} />}


        <TrainingBubble type={BubbleType.TELEOP_PATTERN} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
        {allianceColors.map(c =>
            myFields[c].includes("teleopClassifierState") ?
                <Classifier key={c} color={c} score={scores[c]} setScoreValue={(field, value) => setScoreValue(c, field, value)}
                            field={"teleopClassifierState"}/> : null)}
        <hr/>
    </>
}

export function Penalties({scores, setScoreValue, position}: {
    scores: Record<AllianceColor, DecodeScores>,
    setScoreValue: ScoreTypeSetValue,
    position: RefereePosition
}) {
    const myFields = penaltyFields[position]
    return <>
        <div className="form-group row justify-content-center">
            {allianceColors.map(c => myFields[c].length > 0 ? <div className={`col-12 col-sm-10 col-lg-5 penalties penalties-${c}`} key={c}>
                <span>{c == AllianceColor.RED ? 'Red FOULS' : 'Blue FOULS'}</span>
                {(['ownMinorFouls', 'otherMinorFouls'] as const).map(field => myFields[c].includes(field) ?
                    <Counter key={field} label={"MINOR:"} color={c} megaPenalty={isPenalty(position)}
                             value={scores[c][field]} setValue={(val) => setScoreValue(c, field, val)} /> : null)}
                {(['ownMajorFouls', 'otherMajorFouls'] as const).map(field => myFields[c].includes(field) ?
                    <Counter key={field} label={"MAJOR:"} color={c} megaPenalty={isPenalty(position)}
                             value={scores[c][field]} setValue={(val) => setScoreValue(c, field, val)} /> : null)}
            </div> : null)}
        </div>
    </>
}

export function validationErrors(
    scores: Record<AllianceColor, DecodeScores>,
    phase: MatchPhase,
    position: RefereePosition,
) {
    const errors = []
    for(const c of allianceColors) {
        let fields: (keyof ScoreType)[] = [];
        if (phase == MatchPhase.AUTO) {
            fields = autoFields[position][c];
        } else if (phase == MatchPhase.TELEOP) {
            fields = teleopFields[position][c];
        } else if (phase == MatchPhase.REVIEW) {
            fields = [...autoFields[position][c], ...teleopFields[position][c], ...penaltyFields[position][c]];
        }
        const currentScores = scores[c];
        for (const field of fields) {
            if(typeof currentScores[field] == 'number' && currentScores[field] < 0) {
                errors.push(`Negative value for $[c} - ${field} alliance`);
            }
            if(field == 'autoClassifierState' || field == 'teleopClassifierState') {
                if(invalidArtifactIndexes(currentScores[field]).length > 0) {
                    errors.push(`Artifacts must be contiguous in the ${field.replace('ClassifierState', '')} classifier`);
                }
            }
        }
    }
    return errors;
}