import './Ref.css'
import {useEffect, useReducer, useRef, useState} from "react";
import {useInterval} from "ftc-common/hooks";
import {
    ParsedMatchTiming,
    toggleFullscreen,
    useFullscreenState,
    usePersistentWebsocketWithTime
} from "ftc-common/utils"
import MatchScoring from "./MatchScoring";
import {Loaded, Match, MatchState, RefereePosition, RefereeRole, RefereeStatus, RefMessage, RefUpdate, RefUpdateType, Response, Scores, SessionUpdate, TimeoutUpdate,} from "../javaTypes";
import {AllianceColor} from "ftc-common/javaTypes";
import {t} from 'ftc-common/i18n';
import Timeout from "./Timeout";
import {Button} from "react-bootstrap";

export interface Alliance<T extends Scores> {
    team1 : number,
    team2 : number,
    team3 : number,
    team1Display : string,
    team2Display : string,
    team3Display : string,
    team1Surrogate : boolean,
    team2Surrogate : boolean,
    scores : T,
    scoringStatus : RefereeStatus,
    penaltyStatus : RefereeStatus,
}

export interface RefMatch<T extends Scores> extends Match {
    red : Alliance<T>,
    blue : Alliance<T>,
    lockout?: boolean,
    state: MatchState,
    // For state invalidation
    abortedAt?: Date
}

export enum MatchPhase {
    SELECT,
    LOCKOUT,
    SETUP,
    WAIT,
    AUTO,
    TELEOP,
    REVIEW,
    UNKNOWN
}

interface SetListUpdate {
    type: 'SET_MATCH_LIST',
    matches: RefMatch<any>[]
}

interface RandomizeUpdate {
    type: RefUpdateType.RANDOMIZE,
    match: number,
    random: number
}

interface MatchUpdate {
    type: RefUpdateType.ABORT | RefUpdateType.LOCKOUT,
    match: number
}

interface MatchStartUpdate {
    type: RefUpdateType.START,
    match: number,
    startTime: number
}

interface ScoreUpdate {
    type: RefUpdateType.SCORE_UPDATE,
    match: number,
    data: RefMatch<any>
}

interface AllianceUpdate {
    type:  RefUpdateType.SUBMIT_INIT | RefUpdateType.UNSUBMIT_INIT | RefUpdateType.SUBMIT_AUTO | RefUpdateType.SUBMIT_TELEOP | RefUpdateType.SUBMIT_MATCH,
    match: number,
    position: RefereePosition
}

type MatchListUpdate = SetListUpdate | RandomizeUpdate | MatchUpdate | AllianceUpdate | ScoreUpdate | MatchStartUpdate

interface RefUpdateResponse extends Response {
    payload: RefUpdateResponsePayload
}

export interface RefUpdateResponsePayload {
    status: 'SUCCESS' | 'ERROR',
    message?: string
}

export function positionToAllianceColor(position : RefereePosition) {
    return position === RefereePosition.SCORING_RED || position === RefereePosition.PENALTY_RED ? AllianceColor.RED : AllianceColor.BLUE
}

export function allianceToKey(alliance : AllianceColor) : 'red' | 'blue' {
    return alliance === AllianceColor.RED ? 'red' : 'blue'
}

export function positionToRole(position : RefereePosition) {
    return position === RefereePosition.SCORING_RED || position === RefereePosition.SCORING_BLUE ? RefereeRole.SCORING : RefereeRole.PENALTY
}

export function roleToStatusKey(role : RefereeRole) {
    return role == RefereeRole.SCORING ? 'scoringStatus' : 'penaltyStatus'
}

const BLANK_REF_STATUS = {
    initSubmitted: false,
    autoSubmitted: false,
    teleopSubmitted: false,
    reviewSubmitted: false
}

export function refStatus(match: RefMatch<any>, position: RefereePosition) {
    return match[allianceToKey(positionToAllianceColor(position))][roleToStatusKey(positionToRole(position))];
}

function MatchSelect({position, matchList, setActiveMatchNum} : {
    position: RefereePosition,
    matchList: RefMatch<any>[],
    setActiveMatchNum: (num: number) => void
}) {
    const allianceColor = positionToAllianceColor(position);
    const filteredMatches = matchList.filter(m => !refStatus(m, position).reviewSubmitted && !m.lockout);
    if(filteredMatches.length === 0) {
        return <div className="form-group row justify-content-center">
            <div>No active matches at this time.</div>
        </div>
    }
    return <>
        {filteredMatches.map(m => {
            return <div className="form-group row justify-content-center" key={m.number}>
                <button onClick={() => setActiveMatchNum(m.number)} className={`btn btn-outline-primary btn-lg col-10 mt-2 selectActiveMatch${m.number}Button d-flex flex-wrap justify-content-center pl-1 pr-1`}>
                    <span className="mx-2 inline-block">Match {m.shortName}</span>
                    <span className="mx-2 inline-block redTeams">Red Teams: {m.red.team1Display}, {m.red.team2Display}{m.red.team3 > 0 ? `, ${m.red.team3Display}` : ''}</span>
                    <span className="mx-2 inline-block blueTeams">Blue Teams: {m.blue.team1Display}, {m.blue.team2Display}{m.blue.team3 > 0 ? `, ${m.blue.team3Display}` : ''}</span>
                </button>
            </div>
        })}
    </>
}

function matchReducer(oldList : RefMatch<any>[], update : MatchListUpdate) {
    function updateStatus(statusUpdate : Partial<RefereeStatus>) {
        const aUpdate = update as AllianceUpdate
        const targetField = roleToStatusKey(positionToRole(aUpdate.position))
        const allianceColor = positionToAllianceColor(aUpdate.position);
        return oldList.map(m => {
            if (m.number !== aUpdate.match) {
                return m;
            }
            return { ...m,
                red: allianceColor == AllianceColor.BLUE ? m.red : { ...m.red,
                    [targetField]: { ...m.red[targetField], ...statusUpdate }
                },
                blue: allianceColor == AllianceColor.RED ? m.blue : { ...m.blue,
                    [targetField]: { ...m.blue[targetField], ...statusUpdate }
                },
            }
        })
    }

    switch (update.type) {
        case 'SET_MATCH_LIST':
            return update.matches;
        case RefUpdateType.RANDOMIZE:
            return oldList.map(m => {
                    if(m.number !== update.match) {
                        return m;
                    }
                    return Object.assign<{}, RefMatch<any>, Partial<RefMatch<any>>>({}, m, { state: MatchState.RANDOMIZED, randomization: update.random })
                })
        case RefUpdateType.START:
            return oldList.map(m => {
                if(m.number !== update.match) {
                    return m;
                }
                return Object.assign<{}, RefMatch<any>, Partial<RefMatch<any>>>({}, m, { state: MatchState.AUTO, start: update.startTime })
            })
        case RefUpdateType.ABORT:
            return oldList.map(m => {
                if(m.number !== update.match) {
                    return m;
                }
                // abortedAt is purely for state purging
                return Object.assign<{}, RefMatch<any>, Partial<RefMatch<any>>>({}, m, { state: MatchState.RANDOMIZED,
                    abortedAt: new Date(),
                    red: Object.assign<{}, Alliance<any>, Partial<Alliance<any>>>({}, m.red, { scoringStatus: BLANK_REF_STATUS, penaltyStatus: BLANK_REF_STATUS }),
                    blue: Object.assign<{}, Alliance<any>, Partial<Alliance<any>>>({}, m.blue, { scoringStatus: BLANK_REF_STATUS, penaltyStatus: BLANK_REF_STATUS })
                })
            })
        case RefUpdateType.LOCKOUT:
            return oldList.map(m => {
                if(m.number !== update.match) {
                    return m;
                }
                return Object.assign<{}, RefMatch<any>, Partial<RefMatch<any>>>({}, m, { lockout: true })
            })
        case RefUpdateType.SCORE_UPDATE:
            return oldList.map(m => {
                if(m.number !== update.match) {
                    return m;
                }
                update.data.red.scores = JSON.parse(update.data.red.scores);
                update.data.blue.scores = JSON.parse(update.data.blue.scores);
                return update.data
            })
        case RefUpdateType.SUBMIT_INIT:
            return updateStatus({ initSubmitted: true });
        case RefUpdateType.UNSUBMIT_INIT:
            return updateStatus({ initSubmitted: false });
        case RefUpdateType.SUBMIT_AUTO:
            return updateStatus({ autoSubmitted: true });
        case RefUpdateType.SUBMIT_TELEOP:
            return updateStatus({ teleopSubmitted: true });
        case RefUpdateType.SUBMIT_MATCH:
            return updateStatus({ reviewSubmitted: true });
        default:
            console.error("Unknown update: " + JSON.stringify(update));
            return oldList;
    }
}
const initialNum = window.location.hash.replace("#match-", "");

export default function Ref({event, position, field, fieldCount, timing} : {
    event : string,
    position : RefereePosition,
    field : number,
    fieldCount: number,
    timing: ParsedMatchTiming
}) {
    const { isConnected, now: nowCallback, send } = usePersistentWebsocketWithTime(
        `/stream/ref/?code=${event}&position=${position}&field=${field}`,
        handleMessage);

    const [matchList, dispatchMatchList] = useReducer(matchReducer, []);
    const [activeMatchNum, setActiveMatchNum] = useState(initialNum ? parseInt(initialNum) : null);
    const [lagging, setLagging] = useState<boolean>(false);
    const pendingMessages = useRef<Record<number, [(res : RefUpdateResponsePayload) => void, number]> & { id: number }>({ id: 0});
    const [timeouts, setTimeouts] = useState<TimeoutUpdate | undefined>();
    const fullscreen = useFullscreenState();
    const [conflict, setConflict] = useState(false);
    const [refCount, setRefCount] = useState<Record<string, number>>();

    useEffect(() => {
        function onHashChange() {
            let n = parseInt(window.location.hash.replace("#match-", ""));
            setActiveMatchNum(isNaN(n) ? null : n);
        }
        window.addEventListener("hashchange", onHashChange)
        return () => {
            window.removeEventListener("hashchange", onHashChange)
        }
    }, [])
    function openActiveMatchNum(num : number | null) {
        if(num) {
            window.location.hash = `match-${num}`;
        } else {
            window.location.hash = '';
        }
        setActiveMatchNum(num);
    }

    const activeMatch = matchList.find(m => m.number === activeMatchNum);
    useEffect(() => {
        const activeMatch = matchList.find(m => m.number === activeMatchNum);
        if(activeMatch && refStatus(activeMatch, position).reviewSubmitted) {
            openActiveMatchNum(null);
        }
    }, [activeMatchNum, matchList, position])

    function handleMessage(msg : RefUpdate) {
        if (msg.type === RefUpdateType.RESPONSE) {
            const res = msg as RefUpdateResponse
            const promiseData = pendingMessages.current[res.id];
            if (promiseData) {
                clearTimeout(promiseData[1])
                promiseData[0](res.payload)
            } else {
                console.warn("Received unknown response: " + JSON.stringify(msg))
            }
        } else if (msg.type === RefUpdateType.LOADED) {
            dispatchMatchList({
                type: 'SET_MATCH_LIST', matches: (msg as Loaded).loadedMatches.filter(m => m.field === 0 || field === 0 || m.field === field).map(m => {
                    m.red.scores = JSON.parse(m.red.scores);
                    m.blue.scores = JSON.parse(m.blue.scores);
                    return m;
                })
            })
        } else if (msg.type === RefUpdateType.TIMEOUT) {
            setTimeouts(msg as TimeoutUpdate);
        } else if (msg.type === RefUpdateType.FORCE_RELOAD_CONFIG) {
            // the backend is telling us that the config has changed. This may invalidate our state, so force reload the page to capture new state from backend.
            window.location.reload();
        } else if (msg.type === RefUpdateType.SESSIONS) {
            const conflicts = msg as SessionUpdate;
            if (field === 0) {
                setConflict(Object.values(conflicts.refsByField).reduce((p, c) => p + c, 0) > 1);
                setRefCount(conflicts.refsByField);
            } else {
                const i = field + "";
                setConflict((conflicts.refsByField[i] ?? 0) + (conflicts.refsByField["0"] ?? 0) > 1);
                setRefCount({0: conflicts.refsByField["0"] ?? 0, [i]: conflicts.refsByField[i] ?? 0})
            }
        } else {
            dispatchMatchList(msg as MatchListUpdate);
        }
    }

    function sendMessage(msg : Omit<RefMessage, "id">) : Promise<RefUpdateResponsePayload> {
        const id = pendingMessages.current.id++;
        const ret = new Promise<RefUpdateResponsePayload>((resolve, reject) => {
            pendingMessages.current[id] = [resolve, window.setTimeout(() => {
                delete pendingMessages.current[id]
                reject("timeout")
            }, 1000)]
        });
        send(JSON.stringify(Object.assign({}, msg, { id: id })))
        return ret
    }

    useInterval(() => setLagging(!!activeMatch && activeMatch.start > 0 && (
        // Auto lagging at start of teleop
        (activeMatch.start + (timing.auto.add(timing.transition).total('milliseconds')) < nowCallback() && !refStatus(activeMatch, position).autoSubmitted)
            // dc lagging 10s after buzzer
        || (activeMatch.start + (timing.total.add({ seconds: 10 }).total('milliseconds')) < nowCallback() && !refStatus(activeMatch, position).teleopSubmitted)
    )), 500);

    let phase : [MatchPhase, string] = [MatchPhase.SELECT, t`Match Selection`];
    if(activeMatch) {
        if(activeMatch.lockout) {
            phase = [MatchPhase.LOCKOUT, t`Live Score Lockout`];
        } else if(!refStatus(activeMatch, position).initSubmitted) {
            phase = [MatchPhase.SETUP, t`${activeMatch.shortName} Pre-Match Setup`];
        } else if(activeMatch.state === 'RANDOMIZED' || activeMatch.state === 'UNPLAYED') {
            phase = [MatchPhase.WAIT, t`Wait For Match Start`];
        } else if(!refStatus(activeMatch, position).autoSubmitted) {
            phase = [MatchPhase.AUTO, t`${activeMatch.shortName} AUTO`];
        } else if(!refStatus(activeMatch, position).teleopSubmitted) {
            phase = [MatchPhase.TELEOP, t`${activeMatch.shortName} TELEOP`];
        } else if(!refStatus(activeMatch, position).reviewSubmitted) {
            phase = [MatchPhase.REVIEW, t`${activeMatch.shortName} Review`];
        } else {
            phase = [MatchPhase.UNKNOWN, t`${activeMatch.shortName} unknown state`];
        }
    }

    const shortName = activeMatch?.shortName
    return <div className={`${lagging ? "laggingBlink" : ""} ref-role-${positionToRole(position).toLowerCase()}`}>
        <Timeout timeoutUpdate={timeouts} match={activeMatch} phase={phase[0]} field={field} fieldCount={fieldCount} nowCallback={nowCallback} isConnected={isConnected}/>
        <div className="row justify-content-center">
            <Button className={"col-4 text-center btn btn-success"} style={{margin: "2px"}} onClick={() => toggleFullscreen()}>{fullscreen ? "Exit Fullscreen" : "Fullscreen"}</Button>
        </div>
        <div className="row justify-content-center">
            <div className={`col-10 alert h4 alliance ${positionToAllianceColor(position).toLowerCase()} text-center`}>
                {phase[1]}
                {window.penaltyTabletEnabled ? ` (${positionToRole(position) == RefereeRole.PENALTY ? t`Penalty` : t`Scoring`})` : ''}
                {fieldCount > 1 ? ` (${field == 0 ? t`All\u00A0Fields` : t`Field\u00A0${field}`})` : ''}
            </div>
        </div>
        {isConnected ? null : <div className="dcAlert">
            <div className="dcInner">
                DISCONNECTED!
            </div>
        </div>}
        {conflict ? <div className="alert alert-warning conflictAlert text-center">
            <i className={"fa fa-exclamation-triangle"}/> {t`WARNING! There are multiple referees in the same position! Please check that you are in the right spot!`}<i className={"fa fa-exclamation-triangle ml-1"}/>
            {Object.entries(refCount ?? {}).map(([k,v]) => <div key={k}>{v} {v !== 1 ? "pages" : "page"} bound to {k === "0" ? "all fields" : "field " + k}</div>)}
        </div> : null}
        {phase[0] === MatchPhase.LOCKOUT ? <>
            <div className="form-group row justify-content-center">
                <div className="text-center">
                    {t`The Scorekeeper has locked out editing the scores for match ${shortName}.`}<br/><br/>
                    {t`If you needed to make additional changes, please contact the Scorekeeper ASAP.`}
                </div>
            </div>
            <br/>
            <br/>
            <div className="form-group row justify-content-center">
                <button onClick={() => openActiveMatchNum(null)} className="btn btn-info" role="button">{t`Return to match select`}</button>
            </div>
        </> : (activeMatch ?
            <MatchScoring position={position} match={activeMatch} phase={phase[0]} sendMessage={sendMessage} nowCallback={nowCallback} timing={timing} /> :
            <MatchSelect matchList={matchList} position={position} setActiveMatchNum={openActiveMatchNum} />)}

    </div>
}
