    const timerRef = useRef<HTMLDivElement>(null);
    const fullscreen = useFullscreenState(timerRef);
    const [selectedTimer, setSelectedTimer] = useState<TimeoutReference>();
    const clear = useCallback(() => {
        setSelectedTimer(undefined);
    }, [setSelectedTimer])
    useEffect(() => {
        if(!fullscreen) {
            clear();
        }
    }, [fullscreen]);

    useEffect(() => {
        // If a timeout ends while in fullscreen, clear the selected timer
        if (fullscreen && (!timeoutUpdate?.timeouts.some(x => isEqual(x, selectedTimer)))) {
            disableFullscreen().then(() => clear());
        }
    }, [fullscreen, timeoutUpdate, selectedTimer]);

    const bigTimer = (timeout: TimeoutReference) => document.getElementById("bigTimer")?.requestFullscreen().then(() => {
        setSelectedTimer(timeout);
    });

    const g301Timeout = timeoutUpdate?.timeouts.find(isG301Timeout);
    if (g301Timeout) {
        return <SingleTimeout singleTimeout={g301Timeout} nowCallback={nowCallback} bigTimer={bigTimer} fullscreen={fullscreen} timerRef={timerRef}
                              clear={clear} selectedTimer={selectedTimer} timeoutUpdate={timeoutUpdate} isConnected={isConnected}/>
    } else {
        // TODO
        return null;
    }
