    // }
    //
    // let singleTimeout : TimeoutReference | undefined = timeoutUpdate?.timeouts.find(to => to.field === 0 || to.field === field);
    // if ((leftTimeout?.isElims ?? true) && (field === 0 || fieldCount === 1) && leftTimeout?.field !== 0) {
    //     // SF: during match select/lockout, if unbound or 1-field event, show corner times unless it is a finals TO (or pseudo-finals)
    //     if (phase === MatchPhase.SELECT || phase === MatchPhase.LOCKOUT) {
    //         // TODO if not fullscreen - for FS, need to set which timer is the FS timer. Tap for FS?
    //         return <>
    //             <div className={"timeout row pb-2"}>
    //                 <CornerTimeout nowCallback={nowCallback} timeout={leftTimeout} setBigTimer={bigTimer}/>
    //                 <div className={"col-4 text-sm text-center font-italic"}>{t`Tap timer to fullscreen`}</div>
    //                 <CornerTimeout nowCallback={nowCallback} timeout={rightTimeout} setBigTimer={bigTimer}/>
    //             </div>
    //             <BigTimer nowCallback={nowCallback} timeout={selectedTimer} show={fullscreen} exitFullscreen={clear} isConnected={isConnected}/>
    //         </>
    //     } else if (phase === MatchPhase.SETUP || phase === MatchPhase.WAIT) {
    //         // once in a match screen, pick the timeout that matches the match and single banner it
    //         singleTimeout = timeoutUpdate?.timeouts.find(to => to.field === 0 || to.series === parseInt(match?.shortName[2] ?? "0") );
    //     }
    // }
    // if (!singleTimeout || singleTimeout?.timeoutStart === 0) {
