import Ref from "./Ref";
import {MatchTiming} from "ftc-common/javaTypes";
import LocalErrorBoundary from "../LocalErrorBoundary";
import { createRoot } from "react-dom/client";
import {RefereePosition} from "../javaTypes";
import {parseMatchTiming} from "ftc-common/utils";

declare global {
    interface Window {
        eventCode: string,
        position: RefereePosition,
        field: number,
        fieldCount: number,
        penaltyTabletEnabled: boolean,
        matchTiming: MatchTiming,
    }
}

const container = document.getElementById('reactContainer');
if(!container) {
    console.error("Mount point for container not found")
} else {
    const root = createRoot(container);
    root.render(<LocalErrorBoundary>
        <Ref event={window.eventCode} position={window.position} field={window.field} fieldCount={window.fieldCount} timing={parseMatchTiming(window.matchTiming)} />
    </LocalErrorBoundary>);
}