import {useEffect, useRef, useState} from "react";
import {
    Auto,
    autoFields,
    Init,
    Penalties,
    penaltyFields,
    ScoreType,
    Teleop,
    teleopFields,
    validationErrors
} from "./Decode";
import {MatchType, RefereePosition, RefereeRole, RefMessage, RefMessageType} from "../javaTypes";
import {AllianceColor} from "ftc-common/javaTypes";
import {t} from "ftc-common/i18n";
import {
    allianceToKey,
    MatchPhase,
    positionToAllianceColor,
    positionToRole,
    RefMatch,
    RefUpdateResponsePayload
} from "./Ref";

import './MatchScoring.css';
import TrainingBubble, {BubbleType} from "./TrainingBubble";
import {useStateRef} from "../util";
import Artifact, {randomizationArtifacts} from "../season/decode/Artifact";
import {useInterval} from "ftc-common/hooks";
import {ParsedMatchTiming} from "ftc-common/utils";

export type Robots =  { robot1: number, robot1Display: string, robot2: number, robot2Display: string };

function getNoShowString(scores: ScoreType, teamPos: 1 | 2 | 3, isPlayoff: boolean) {
    if (!scores[`noshow${teamPos}`]) {
        return ""; //
    }
    if (scores[`noshow${teamPos}`] === 1 && !isPlayoff) return "No Show";
    if (scores[`noshow${teamPos}`] === 2 || isPlayoff) return "No Robot";
}

function hasNoRobot(scores: ScoreType, teamPos: 1 | 2 | 3) {
    return scores[`noshow${teamPos}`] > 0;
}

function ShowRandomization({alliance, randomization} : {
    alliance : AllianceColor,
    randomization: number,
}) {
    const artifacts = randomizationArtifacts[randomization];

    return <div className={`form-group row justify-content-center`}>
        <div className="col-12 text-center"><b>Randomization:</b></div>
        <div className="col-12 text-center">
            <div className={"randomizationWrapper"}>
                <div className={"artifacts"}>
                    {artifacts?.map((artifact, index) => (
                        <Artifact key={index} value={artifact} />
                    ))}
                </div>
            </div>
        </div>
        <div className={"col-12 text-center"}>
            <span className={"positionSpan"}>MOTIF {randomization} (ID 2{randomization})</span>
        </div>
    </div>;
}

function filterFields(position: RefereePosition) {
    const filterRedFields = [...autoFields[position].RED, ...teleopFields[position].RED, ...penaltyFields[position].RED]
    const filterBlueFields = [...autoFields[position].BLUE, ...teleopFields[position].BLUE, ...penaltyFields[position].BLUE]
    // Scoring referee is responsible for init fields
    if(positionToRole(position) == RefereeRole.SCORING) {
        const target = positionToAllianceColor(position) == AllianceColor.RED ? filterBlueFields : filterRedFields;
        for (const num of [1, 2, 3] as const) {
            target.push(`noshow${num}`);
        }
        for (const num of [1, 2] as const) {
            target.push(`dq${num}`);
        }
    }
    return { redFields: filterRedFields, blueFields: filterBlueFields }
}

export default function MatchScoring({position, match, phase, sendMessage, nowCallback, timing} : {
    position: RefereePosition,
    match: RefMatch<ScoreType>,
    phase: MatchPhase,
    sendMessage: (msg : Omit<RefMessage, "id">) => Promise<RefUpdateResponsePayload>,
    nowCallback: () => number,
    timing: ParsedMatchTiming
}) {
    const [currentRedScores, setRedScores, currentRedScoresRef] = useStateRef(match.red.scores);
    const [currentBlueScores, setBlueScores, currentBlueScoresRef] = useStateRef(match.blue.scores);
    const prevMatchRef = useRef<RefMatch<ScoreType>>();
    const [errorMessage, setErrorMessage] = useState<string | null>(null);
    const [currentBubble, setCurrentBubble] = useState<BubbleType>(match.training ? BubbleType.TRAINING_INTRO : BubbleType.NO_TRAINING);

    useEffect(() => {
        if(!prevMatchRef.current || prevMatchRef.current.type !== match.type || prevMatchRef.current.number !== match.number || prevMatchRef.current?.abortedAt !== match.abortedAt) {
            setRedScores(match.red.scores);
            setBlueScores(match.blue.scores);
        } else {
            const { redFields, blueFields } = filterFields(position);
            setRedScores((was) => {
                // Select all fields that are not owned by this referee for updating
                const partialScores = Object.fromEntries(
                    Object.entries(match.red.scores).filter(
                        ([key, val])=> !(redFields).includes(key as keyof ScoreType)
                    )
                )
                return {...was, ...partialScores}
            })
            setBlueScores((was) => {
                // Select all fields that are not owned by this referee for updating
                const partialScores = Object.fromEntries(
                    Object.entries(match.blue.scores).filter(
                        ([key, val])=> !(blueFields).includes(key as keyof ScoreType)
                    )
                )
                return {...was, ...partialScores}
            })
        }
        prevMatchRef.current = match
    }, [position, match]);

    async function sendScores(type : RefMessageType, newScores?: { scores : ScoreType, color: AllianceColor }) {
        setErrorMessage(null)
        const redScores = (newScores && newScores.color == AllianceColor.RED ? newScores.scores : currentRedScoresRef.current!);
        const blueScores = (newScores && newScores.color == AllianceColor.BLUE ? newScores.scores : currentBlueScoresRef.current!);

        const { redFields, blueFields } = filterFields(position);

        const partialRedScores = Object.fromEntries(
            Object.entries(redScores).filter(
                ([key, val])=> (redFields).includes(key as keyof ScoreType)
            )
        )
        const partialBlueScores = Object.fromEntries(
            Object.entries(blueScores).filter(
                ([key, val])=> (blueFields).includes(key as keyof ScoreType)
            )
        )
        const res = await sendMessage({type: type, match: match.number,
            redScoreUpdateString: JSON.stringify(partialRedScores),
            blueScoreUpdateString: JSON.stringify(partialBlueScores)
        })
        if(res.status !== 'SUCCESS') {
            setErrorMessage(res.message || null)
            setTimeout(() => setErrorMessage(null), type == RefMessageType.SUBMIT_MATCH ? 10000 : 3000)
            return false;
        }
        return true;
    }

    useInterval(() => {
        if(phase == MatchPhase.AUTO && positionToRole(position) == RefereeRole.PENALTY && match.start + (timing.auto.add({ seconds: 1}).total('milliseconds')) < nowCallback()) {
            // Penalty refs auto-submit auto since they should not review anything at that time
            sendScores(RefMessageType.SUBMIT_AUTO)
        }
    }, 500)

    function setScoreValue<K extends keyof ScoreType>(alliance: AllianceColor, key: K, value: ScoreType[K]) {
        const func = alliance === AllianceColor.RED ? setRedScores : setBlueScores;
        func((was : ScoreType) => {
            const newScores = Object.assign<{}, ScoreType, Partial<ScoreType>>({}, was, {[key]: value})

            if(phase === MatchPhase.REVIEW) {
                sendScores(RefMessageType.QUIET_SCORE_UPDATE, { color: alliance, scores: newScores })
            } else {
                sendScores(RefMessageType.SCORE_UPDATE, { color: alliance, scores: newScores })
            }
            return newScores;
        })
    }

    function calculateRobots(ns1 : number, ns2 : number, ns3 : number, alliance : AllianceColor) {
        const tempRobots : Robots = { robot1: 0, robot1Display: '', robot2: 0, robot2Display: '' };
        if (match.type === 'ELIMS') {
            const allTeams = [
                ns1 ? null : [match[allianceToKey(alliance)].team1, match[allianceToKey(alliance)].team1Display],
                ns2 ? null : [match[allianceToKey(alliance)].team2, match[allianceToKey(alliance)].team2Display],
                ns3 ? null : [match[allianceToKey(alliance)].team3, match[allianceToKey(alliance)].team3Display]
            ].filter(t => t) as [number, string][];
            const team1 = allTeams[0] || [0, ''];
            const team2 = allTeams[1] || [0, ''];
            tempRobots.robot1 = team1[0];
            tempRobots.robot2 = team2[0];
            tempRobots.robot1Display = team1[1];
            tempRobots.robot2Display = team2[1];
        } else {
            tempRobots.robot1 = ns1 ? 0 : match[allianceToKey(alliance)].team1;
            tempRobots.robot2 = ns2 ? 0 : match[allianceToKey(alliance)].team2;
            tempRobots.robot1Display = ns1 ? '' : match[allianceToKey(alliance)].team1Display;
            tempRobots.robot2Display = ns2 ? '' : match[allianceToKey(alliance)].team2Display;
        }
        return tempRobots;
    }

    const redRobots = calculateRobots(currentRedScores.noshow1, currentRedScores.noshow2, currentRedScores.noshow3, AllianceColor.RED);
    const blueRobots = calculateRobots(currentBlueScores.noshow1, currentBlueScores.noshow2, currentBlueScores.noshow3, AllianceColor.BLUE);

    const preloadTarget = ((match.randomization - 1) % 3) + 1;

    const submitPhaseAndScroll = async (phase : RefMessageType) => {
        if (await sendScores(phase)) {
            window.scrollTo(0, 0);
        }
    }

    const scoreProps = {
        scores: {
            [AllianceColor.RED]: currentRedScores,
            [AllianceColor.BLUE]: currentBlueScores
        },
        position,
        robots: {
            [AllianceColor.RED]: redRobots,
            [AllianceColor.BLUE]: blueRobots
        },
        preloadTarget,
        setScoreValue,
        match
    }

    const invalidMessages = validationErrors(scoreProps.scores, phase, position)
    const errorDisplay = <div className="col-10 text-center">
        {invalidMessages.join(". ")}
        {errorMessage}
    </div>

    // for Decode, the ref does init for the opposite alliance
    const initAlliance= positionToAllianceColor(position) == AllianceColor.RED ? AllianceColor.BLUE : AllianceColor.RED;
    const initDisplayColor = initAlliance === AllianceColor.RED ? 'Red' : 'Blue';
    const setupScores = initAlliance == AllianceColor.RED ? currentRedScores : currentBlueScores;
    const threeTeamAlliance = match[allianceToKey(initAlliance)].team3 > 0
    // At least 1 no show is selected
    const activeTeamsSelected = !threeTeamAlliance || [setupScores.noshow1, setupScores.noshow2, setupScores.noshow3].some(ns => ns > 0)
    switch (phase) {
        case MatchPhase.SETUP:
            return <div>
                <TrainingBubble type={BubbleType.TRAINING_INTRO} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <TrainingBubble type={BubbleType.INIT} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <TrainingBubble type={BubbleType.NO_SHOW} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <Init match={scoreProps.match} scores={scoreProps.scores} robots={scoreProps.robots} alliance={initAlliance} isReview setupScores={setupScores} setScoreValue={scoreProps.setScoreValue}/>
                <hr/>
                <TrainingBubble type={BubbleType.SUBMIT_INIT} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <div className="row justify-content-center">
                    <button className="btn col-6 text-center btn-secondary" onClick={() => sendScores(RefMessageType.SUBMIT_INIT)}
                            disabled={!activeTeamsSelected}>
                        {t`${initDisplayColor} Alliance Ready`}
                    </button>
                    {errorDisplay}
                </div>
            </div>
        case MatchPhase.WAIT:
            return <div>
                <TrainingBubble type={BubbleType.WAIT_FOR_START} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble} match={match}/>
                <div className="form-group row justify-content-center">
                    <div
                        className="col-10">{t`Waiting for match to start. This page will automatically load when the match has started.`}</div>
                </div>
                <div className="row justify-content-center">
                    <h3 className="col-10">{t`Waiting for Match ${match.shortName}`}</h3>
                </div>
                <br/>
                <div className="row justify-content-center text-center">
                    <table className={"w-100 waitingTeamsTable "+initAlliance}>
                        <tbody>
                           <tr className={"h3"}>
                               <td colSpan={match[allianceToKey(initAlliance)].team3 > 0 ? 3: 2} className={"text-center"}>{initDisplayColor} Alliance Teams:</td>
                           </tr>
                            <tr className="h3">
                                <td>
                                    {match[allianceToKey(initAlliance)].team1Display}
                                </td>
                                <td>
                                    {match[allianceToKey(initAlliance)].team2Display}
                                </td>
                                {match[allianceToKey(initAlliance)].team3 > 0 ? <td>
                                    {match[allianceToKey(initAlliance)].team3Display}
                                </td> : null}
                            </tr>
                            <tr>
                                <td>
                                    {hasNoRobot(setupScores, 1) ? <span className="noShow">{getNoShowString(setupScores, 1, match.type == MatchType.ELIMS)}</span> : null}
                                </td>
                                <td>
                                    {hasNoRobot(setupScores, 2) ? <span className="noShow">{getNoShowString(setupScores, 2, match.type == MatchType.ELIMS)}</span> : null}
                                </td>
                                {match[allianceToKey(initAlliance)].team3 > 0 ? <td>
                                    {hasNoRobot(setupScores, 3) ? <span className="noShow">{getNoShowString(setupScores, 3, match.type == MatchType.ELIMS)}</span> : null}
                                </td> : null}
                            </tr>
                        </tbody>
                    </table>
                </div>
                <br/>
                {positionToRole(position) == RefereeRole.SCORING ? <div className="row justify-content-center">
                    <button className="btn col-6 text-center btn-secondary" onClick={() => sendScores(RefMessageType.UNSUBMIT_INIT)}>
                        Edit Pre-Match Setup
                    </button>
                </div> : null}
                <br/><br/>
                {/*<TrainingBubble type={BubbleType.RANDOMIZED} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble} match={match}/>*/}
                {match.randomization < 0 ? <div className="row justify-content-center">
                    <div className="col-10">Match has not been randomized. This page will update once the randomization
                        has been decided
                    </div>
                </div> : <ShowRandomization alliance={positionToAllianceColor(position)} randomization={match.randomization}/> }
            </div>
        case MatchPhase.AUTO:
            return <div>
                <TrainingBubble type={BubbleType.AUTO} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <TrainingBubble type={BubbleType.AUTO_2} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                {positionToRole(position) == RefereeRole.SCORING ? <div className="row justify-content-center">
                    <button className="btn col-6 text-center btn-secondary mb-2" onClick={() => sendScores(RefMessageType.UNSUBMIT_INIT)}>
                        Edit Pre-Match Setup
                    </button>
                </div> : null}
                <Auto {...scoreProps} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble} />
                <div className="row justify-content-center">
                    {positionToRole(position) == RefereeRole.SCORING ? <button className="btn col-6 text-center btn-secondary"  onClick={() => submitPhaseAndScroll(RefMessageType.SUBMIT_AUTO)}
                            disabled={invalidMessages.length > 0}>
                        {t`Submit AUTO`}
                    </button> : null}
                    {errorDisplay}
                </div>
            </div>
        case MatchPhase.TELEOP:
            return <div>
                <TrainingBubble type={BubbleType.TELEOP} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <Teleop {...scoreProps} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble} />
                <TrainingBubble type={BubbleType.TELEOP_END} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                <div className="row justify-content-center">
                    <button className="btn col-6 text-center btn-secondary"  onClick={() => submitPhaseAndScroll(RefMessageType.SUBMIT_TELEOP)}
                            disabled={invalidMessages.length > 0}>
                        {t`Submit TELEOP`}
                    </button>
                    {errorDisplay}
                </div>
            </div>
        case MatchPhase.REVIEW:
            return <div>
                <TrainingBubble type={BubbleType.REVIEW} currentBubble={currentBubble} setCurrentBubble={setCurrentBubble}/>
                {positionToRole(position) == RefereeRole.SCORING ? <>
                <div className="row justify-content-center">
                    <div className="col-10 alert alert-dark text-center">
                        Pre-MATCH
                    </div>
                </div>
                <Init match={scoreProps.match} scores={scoreProps.scores} robots={scoreProps.robots} alliance={initAlliance} isReview setupScores={setupScores} setScoreValue={scoreProps.setScoreValue}/>
                </> : null}
                {autoFields[position].RED.length > 0 || autoFields[position].BLUE.length > 0 ? <div className="row justify-content-center">
                    <div className="col-10 alert alert-dark text-center">
                        AUTO Scores
                    </div>
                </div> : null}
                <Auto {...scoreProps} isReview />
                {teleopFields[position].RED.length > 0 || teleopFields[position].BLUE.length > 0 ? <div className="row justify-content-center">
                    <div className="col-10 alert alert-dark text-center">
                        TELEOP Scores
                    </div>
                </div> : null}
                <Teleop {...scoreProps} isReview />
                <Penalties {...scoreProps} />
                <div className="row justify-content-center">
                    <button className="btn col-6 text-center btn-secondary"  onClick={() => sendScores(RefMessageType.SUBMIT_MATCH)}
                            disabled={invalidMessages.length > 0 || !activeTeamsSelected}>
                        {t`Submit Final Scores`}
                    </button>
                    {errorDisplay}
                </div>
            </div>
    }
    return <>unknown phase</>;
}