import { t } from "ftc-common/i18n";
import {ScoreType} from "./Decode";
import {RefMatch} from "./Ref";
import { CSSProperties, useEffect, useState } from "react";

export enum BubbleType {
    TRAINING_INTRO,
    INIT,
    NO_SHOW,
    SUBMIT_INIT,
    WAIT_FOR_START,
    RANDOMIZED,
    AUTO,
    AUTO_2,
    AUTO_SAMPLES_SPECIMENS,
    AUTO_LOCATION,
    AUTO_FOULS,
    AUTO_PATTERN,
    AUTO_SUBMIT,
    TELEOP,
    TELEOP_ARTIFACT,
    TELEOP_LOCATION,
    TELEOP_DEPOT,
    TELEOP_FOULS,
    TELEOP_PATTERN,
    TELEOP_END,
    REVIEW,
    NO_TRAINING
}

enum BubbleLocation {
    TOP,
    INLINE
}

interface BubbleData {
    location: BubbleLocation,
    onClose?: Function,
    isVisible?: (currentBubble: BubbleType, match?: RefMatch<ScoreType>) => boolean, // if the check is more complicated than just currentBubble == this
    content: string,
    classes?: string,
    canGoBack?: boolean,
    canGoForward?: (currentBubble: BubbleType, match? : RefMatch<ScoreType>) => boolean
}

function getBubbleContent(type : BubbleType) : string {
    switch (type) {
        case BubbleType.TRAINING_INTRO: return t`This Test Match has been marked as a Training Match. Informative bubbles will 
                step through the important parts of the scoring REFEREE workflow.`;
        case BubbleType.INIT: return t`This is the Pre-MATCH Setup page. Enter information about the teams present. The color banner 
                should match the color of the ALLIANCE AREA nearest to you. On this page, you are entering the status of the teams in 
                the ALLIANCE AREA across from you. Their ROBOTS are on your side of the FIELD.`;
        case BubbleType.NO_SHOW: return t`For each team, mark whether they are present for the MATCH. Per G208, the minimum requirement 
                to be "Present" is a DRIVE TEAM member. If a DRIVE TEAM member is in the ALLIANCE AREA but has no ROBOT, select "No Robot."
                If no DRIVE TEAM member is at the FIELD, mark the team as "No Team." During playoffs, "No Team" will no longer be an option.`;
        case BubbleType.SUBMIT_INIT: return t`After filling out this page, click the "Alliance Ready" button. If you need to edit these inputs,
                you can return to this page until the end of AUTO.`;
        case BubbleType.WAIT_FOR_START: return t`This is the Wait For MATCH Start page. It will automatically transition to AUTO when the MATCH starts.
                Click the gray button if you need to return to the Pre-MATCH Setup page.`;
        case BubbleType.AUTO: return t`This page is for recording AUTO scoring. After scoring AUTO, click the Submit button 
                to advance to the TELEOP screen. Even if you have questions about AUTO, submit what you can and move on so you don't miss achievements.
                You can make edits to the AUTO scores in the Review screen following TELEOP.
                The page will blink yellow if you have not advanced to TELEOP in time.<br/>
                (For this Training Match, don't worry about the timing & yellow blinking.)`;
        case BubbleType.AUTO_2: return t`For in-MATCH scoring, you are scoring achievements that occur on 
                your side of the FIELD. This will include achievements by both ALLIANCES. You are looking at the GOAL immediately adjacent to you and the ROBOTS that start on 
                your side of the FIELD, which should match the color of the inputs.`;
        case BubbleType.AUTO_SAMPLES_SPECIMENS: return t`Use the top two inputs to record the number of ARTIFACTS that enter 
                the GOAL, exit under the archway, and pass through the SQUARE. If the ARTIFACT passes through the SQUARE and
                transitions directly to the RAMP, count it as CLASSIFIED. If the ARTIFACT passes through the SQUARE but does 
                not directly transition to the RAMP, count it as OVERFLOW.` ;
        case BubbleType.AUTO_LOCATION: return t`For each ROBOT that started on your half of the FIELD, check their location at the end of AUTO (approximately at the start of the buzzer). 
                To count for LEAVE points (mark as "Yes"), the ROBOT must be not be over any LAUNCH LINE (the lines of the white triangles 
                and the line at the base of the GOAL). Otherwise, mark them as "No."`;
        case BubbleType.AUTO_FOULS: return t`Enter any FOULS communicated to you by the gameplay REFEREE during the MATCH. FOUL counts are shared between 
                AUTO and TELEOP. You can enter FOULS for either ALLIANCE, but you will not see FOUL counts entered by other REFEREES. When entering a FOUL,
                ensure you enter the correct FOUL type for the correct ALLIANCE.`
        case BubbleType.AUTO_PATTERN: return t`As AUTO ends, ARTIFACTS on the RAMP contained by the GATE are recorded for PATTERN scoring.
                Starting at the GATE (first input, nearest the bottom of the RAMP), record the color of each ARTIFACT directly on the RAMP
                in the order they are on the RAMP by selecting either "GREEN" or "PURPLE," regardless of how they got there. If only 5 
                ARTIFACTS are on the RAMP, only 5 colors should be recorded, starting at the GATE. The rest (6-9) should remain with the default "NONE" (white circle).
                `;
        case BubbleType.AUTO_SUBMIT: return t`After scoring AUTO, click the Submit button to advance to the TELEOP screen. 
                Even if you have questions about AUTO, submit what you can and move on so you don't miss achievements.
                You can make edits to the AUTO scores in the Review screen following TELEOP.`
        // "Field-state and" remove
        case BubbleType.TELEOP: return t`This page is for recording TELEOP scoring. FOUL counts have carried over from AUTO.`;
        case BubbleType.TELEOP_ARTIFACT: return t`Continue to score OVERFLOW and CLASSIFIED ARTIFACTS. `;
        case BubbleType.TELEOP_LOCATION: return t`At the end of the MATCH (T=0:00), look at the BASE ZONE near you. Record 
                if each of the ROBOTS has met fully or partially returned criteria. A fully returned ROBOT must be only supported, 
                either directly or transitively, by the BASE ZONE. A partially returned ROBOT must be partially supported either 
                directly or transitively, by the BASE ZONE.`
        case BubbleType.TELEOP_DEPOT: return t`After the end of the MATCH, check the DEPOT nearest you and score the number of ARTIFACTS over the DEPOT line.`;
        case BubbleType.TELEOP_FOULS: return t`Continue to add FOULS communicated to you by the gameplay REFEREE throughout the MATCH. 
                Ensure you enter the correct FOUL type for the correct ALLIANCE.`;
        case BubbleType.TELEOP_PATTERN: return t`After the FIELD has come to rest, ARTIFACTS on the RAMP contained by the GATE are recorded for PATTERN scoring.
                Starting at the GATE (first input, nearest the bottom of the RAMP), record the color of each ARTIFACT directly on the RAMP
                in the order they are on the RAMP by selecting either "GREEN" or "PURPLE," regardless of how they got there. If only 5 
                ARTIFACTS are on the RAMP, only 5 colors should be recorded, starting at the GATE. The rest (6-9) should remain with the default 
                "NONE" (white circle).`;
        case BubbleType.TELEOP_END: return t`Save any REFEREE discussions for the review phase, during which AUTO, TELEOP, and FOULS can be edited. Clicking "Submit TELEOP" 
                will transition to the Review page. If you have not submitted within 10 seconds, the page will flash yellow.`
        case BubbleType.REVIEW: return t`The Review page lists the scores entered for both AUTO and TELEOP periods. Any edits 
                done here will not reflect in the live scores shown on the displays. Confirm with the gameplay REFEREE that you have recorded all the FOULS correctly.
                Once you have finalized the scores, click "Submit Final Scores." 
                Once you submit, only the scorekeeper can edit the scores.`
    }
    return "Test";
}

function getBubbleData(type : BubbleType) : BubbleData {
    const content = getBubbleContent(type);
    const toTrue = () => true;
    switch (type) {
        case BubbleType.TRAINING_INTRO: return {location: BubbleLocation.TOP, content: content, canGoForward: toTrue};
        case BubbleType.INIT: return {location: BubbleLocation.TOP,  content: content, canGoBack: true, classes: "small", canGoForward: toTrue};
        case BubbleType.NO_SHOW: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, classes:"small", canGoForward: toTrue};
        case BubbleType.SUBMIT_INIT: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true};
        case BubbleType.WAIT_FOR_START: return {location: BubbleLocation.TOP,  content: content};
        case BubbleType.AUTO: return {location: BubbleLocation.TOP,  content: content, canGoForward: toTrue, classes: "small", isVisible: currentBubble => currentBubble <= BubbleType.AUTO};
        case BubbleType.AUTO_2: return {location: BubbleLocation.TOP,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.AUTO_SAMPLES_SPECIMENS: return {location: BubbleLocation.INLINE,  content: content, classes:"small", canGoBack: true, canGoForward: toTrue};
        case BubbleType.AUTO_LOCATION: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.AUTO_FOULS: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.AUTO_PATTERN: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, classes: "small"};
        case BubbleType.AUTO_SUBMIT: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true};
        case BubbleType.TELEOP: return {location: BubbleLocation.TOP,  content: content, canGoForward: toTrue, isVisible: currentBubble => currentBubble <= BubbleType.TELEOP};
        case BubbleType.TELEOP_ARTIFACT: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.TELEOP_DEPOT: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.TELEOP_FOULS: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.TELEOP_LOCATION: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue};
        case BubbleType.TELEOP_PATTERN: return {location: BubbleLocation.INLINE,  content: content, canGoBack: true, canGoForward: toTrue, classes: "small"};
        case BubbleType.TELEOP_END: return {location: BubbleLocation.INLINE,  content: content, classes: "small", canGoBack: true};
        case BubbleType.REVIEW: return {location: BubbleLocation.TOP,  content: content, classes: "small", isVisible: currentBubble => currentBubble <= BubbleType.REVIEW};
        default: return {location: BubbleLocation.INLINE, content: "Error - Unknown Training Bubble!"};
    }
}

export default function TrainingBubble({type, currentBubble, setCurrentBubble, match} : {
    type: BubbleType,
    currentBubble?: BubbleType,
    setCurrentBubble?: (currentBubble : BubbleType) => void,
    match?: RefMatch<ScoreType>
}) {
    const data = getBubbleData(type);

    useEffect(() => {
        const elem = document.getElementById("bubble_" + type);
        /*
            Because this hook is called before the visibility check, it will also be called as it is being unmounted when currentBubble increments,
            so elem may be null. This also allows it to work for the back button.
         */
        if (elem) {
            elem.scrollIntoView({behavior: 'smooth'});
        }
    }, [type, currentBubble]);


    if ((data.isVisible === undefined && currentBubble !== type) || (data.isVisible !== undefined && currentBubble !== undefined && !data.isVisible(currentBubble, match))) {
        return null;
    }
    const isTop = data.location === BubbleLocation.TOP;
    const style: CSSProperties = isTop ? {position: 'fixed', top: 0} : {position: 'absolute', bottom: 5, left: 15};
    const hasNext = data.canGoForward !== undefined && currentBubble !== undefined && data.canGoForward(currentBubble, match);
    const bubbleContent = <div id={"bubble_" + type} className={`bubble ${isTop ? "container" : ""} ${data.classes}`} style={style} >
        <div dangerouslySetInnerHTML={{ '__html': data.content }}/>
        <div className={"w-100 text-center"}>
            {data.canGoBack ? <button className={"btn btn-secondary btn-sm"} onClick={setCurrentBubble ? () => setCurrentBubble(type - 1) : undefined}>{t`Back`}</button> : null}
            <button className={"btn btn-secondary btn-sm m-1 ml-4"} onClick={setCurrentBubble ? () => setCurrentBubble(type + 1) : undefined}>{hasNext ? t`Next` : t`Close`}</button>
        </div>
    </div>

    return isTop ? bubbleContent : <div className={"bubbleWrap w-100"} style={{position: 'relative'}}>{bubbleContent}</div>;
}